import { CircleAlert } from "lucide-react";
import React, { Fragment } from "react";

import { Badge } from "@/components/ui/badge";
import {
  Breadcrumb,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbList,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from "@/components/ui/breadcrumb";
import { Separator } from "@/components/ui/separator";
import { SidebarTrigger } from "@/components/ui/sidebar";
import { getGlobalLinkComponent } from "@/components/fsui/fscommon";

import { usePageInfo } from "./store";

export const PageHeader = () => {
  const Link = getGlobalLinkComponent();
  const pageInfo = usePageInfo();

  return (
    <Fragment>
      <title>{pageInfo.title}</title>
      <header className="flex h-16 shrink-0 items-center gap-2">
        <div className="flex flex-1 items-center gap-2 px-4">
          <SidebarTrigger className="-ml-1 cursor-pointer" />
          <Separator
            orientation="vertical"
            className="mr-2 data-[orientation=vertical]:h-4"
          />
          {(pageInfo?.breadcrumbs?.length ?? 0) > 0 && (
            <Breadcrumb>
              <BreadcrumbList>
                {pageInfo?.breadcrumbs?.map((breadcrumb, index, array) => {
                  const isLast = index === array.length - 1;
                  return (
                    <React.Fragment
                      key={`${breadcrumb.title}-${breadcrumb.href ?? index}`}
                    >
                      <BreadcrumbItem className="hidden md:block">
                        {isLast ? (
                          <BreadcrumbPage>{breadcrumb.title}</BreadcrumbPage>
                        ) : (
                          <BreadcrumbLink
                            asChild
                            href={breadcrumb.href}
                          >
                            <Link
                              href={breadcrumb.href}
                              title={breadcrumb.title}
                            >
                              {breadcrumb.title}
                            </Link>
                          </BreadcrumbLink>
                        )}
                      </BreadcrumbItem>
                      {!isLast && (
                        <BreadcrumbSeparator className="hidden md:block" />
                      )}
                    </React.Fragment>
                  );
                })}
              </BreadcrumbList>
            </Breadcrumb>
          )}
        </div>
        <div className="ml-auto px-4">
          <div className="flex items-center gap-2 text-sm">
            {pageInfo.actions}
            {pageInfo.hasUnsavedChanges && (
              <Badge
                variant="destructive"
                className="mr-1 select-none"
              >
                <CircleAlert className="mr-1 inline-block h-4 w-4 align-middle" />
                Unsaved changes
              </Badge>
            )}
          </div>
        </div>
      </header>
    </Fragment>
  );
};

