import { ChevronRight, MoreHorizontal, type LucideIcon } from "lucide-react";

import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  SidebarMenuAction,
  SidebarMenuSub,
  SidebarMenuSubButton,
  SidebarMenuSubItem,
} from "@/components/ui/sidebar";
import { getGlobalLinkComponent } from "@/components/fsui/fscommon";

import type { ReactNode } from "react";

export interface MenuGroupData {
  group: string;
  items: MenuItemData[];
}

export interface MenuItemData {
  title: string;
  url?: string;
  icon?: LucideIcon;
  isActive?: boolean;
  items?: MenuItemData[];
  actions?: {
    key: string;
    element: ReactNode;
    onClick?: () => void;
  }[];
}

export const isActiveSidebarMenuItem = (
  item: MenuItemData,
  currentPath: string,
): boolean => {
  if (
    item.url !== undefined &&
    (item.url === currentPath ||
      (item.url !== "/" && currentPath.startsWith(item.url)))
  ) {
    return true;
  }

  if (item.items) {
    for (const subItem of item.items) {
      if (isActiveSidebarMenuItem(subItem, currentPath)) {
        return true;
      }
    }
  }

  return false;
};

// Recursive component to render nested menu items
export const NestedMenuItem = ({
  item,
  currentPath,
  isMobile,
}: {
  item: MenuItemData;
  currentPath: string;
  isMobile?: boolean;
}) => {
  const Link = getGlobalLinkComponent();
  const isActive = isActiveSidebarMenuItem(item, currentPath);
  const actionsElement =
    (item?.actions?.length ?? 0) > 0 ? (
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <SidebarMenuAction
            showOnHover
            className="cursor-pointer"
          >
            <MoreHorizontal />
            <span className="sr-only">More</span>
          </SidebarMenuAction>
        </DropdownMenuTrigger>
        <DropdownMenuContent
          className="w-48"
          side={isMobile ? "bottom" : "right"}
          align={isMobile ? "end" : "start"}
        >
          {item?.actions?.map((action) => (
            <DropdownMenuItem
              key={action.key}
              onClick={action.onClick}
              className="cursor-pointer"
            >
              {action.element}
            </DropdownMenuItem>
          ))}
        </DropdownMenuContent>
      </DropdownMenu>
    ) : null;

  if (!item.items || item.items.length === 0) {
    return (
      <SidebarMenuSubItem>
        <SidebarMenuSubButton
          asChild
          isActive={isActive}
        >
          <Link href={item.url}>
            <span>{item.title}</span>
          </Link>
        </SidebarMenuSubButton>
        {actionsElement}
      </SidebarMenuSubItem>
    );
  }

  return (
    <SidebarMenuSubItem>
      <Collapsible defaultOpen={isActive}>
        <CollapsibleTrigger asChild>
          <SidebarMenuSubButton
            asChild
            isActive={isActive}
          >
            <Link href={item.url}>
              <span>{item.title}</span>
              <ChevronRight className="ml-auto transition-transform duration-200 group-data-[state=open]/collapsible:rotate-90" />
            </Link>
          </SidebarMenuSubButton>
          {actionsElement}
        </CollapsibleTrigger>
        <CollapsibleContent>
          <SidebarMenuSub>
            {item.items.map((subItem) => (
              <NestedMenuItem
                key={subItem.title}
                item={subItem}
                currentPath={currentPath}
              />
            ))}
          </SidebarMenuSub>
        </CollapsibleContent>
      </Collapsible>
    </SidebarMenuSubItem>
  );
};

import { ChevronRight } from "lucide-react";
import { Fragment, useEffect, useState } from "react";

import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import {
  SidebarGroup,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuAction,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarMenuSub,
} from "@/components/ui/sidebar";
import { getGlobalLinkComponent } from "@/components/fsui/fscommon";

import {
  isActiveSidebarMenuItem,
  NestedMenuItem,
  type MenuGroupData,
  type MenuItemData,
} from "./menu";

const CollapsibleMenuGroup = ({
  item,
  currentUrl,
  isMobile,
}: {
  item: MenuItemData;
  currentUrl: string;
  isMobile?: boolean;
}) => {
  const Link = getGlobalLinkComponent();
  const isActive = isActiveSidebarMenuItem(item, currentUrl);
  const [open, setOpen] = useState(isActive);
  useEffect(() => {
    setOpen(isActive);
  }, [isActive]);

  return (
    <Collapsible
      key={item.url || item.title}
      asChild
      defaultOpen={isActive}
      open={open}
      onOpenChange={setOpen}
    >
      <SidebarMenuItem>
        {item.url === undefined ? (
          <CollapsibleTrigger asChild>
            <SidebarMenuButton
              tooltip={item.title}
              isActive={isActive}
              className="cursor-pointer"
            >
              {item.icon && <item.icon />}
              <span>{item.title}</span>
            </SidebarMenuButton>
          </CollapsibleTrigger>
        ) : (
          <SidebarMenuButton
            asChild
            tooltip={item.title}
            isActive={isActive}
          >
            <Link
              href={item.url}
              title={item.title}
            >
              {item.icon && <item.icon />}
              <span>{item.title}</span>
            </Link>
          </SidebarMenuButton>
        )}
        {item.items?.length ? (
          <Fragment>
            <CollapsibleTrigger asChild>
              <SidebarMenuAction className="cursor-pointer data-[state=open]:rotate-90">
                <ChevronRight />
                <span className="sr-only">Toggle</span>
              </SidebarMenuAction>
            </CollapsibleTrigger>
            <CollapsibleContent>
              <SidebarMenuSub>
                {item.items.map((subItem) => (
                  <NestedMenuItem
                    key={subItem.title}
                    item={subItem}
                    currentPath={currentUrl}
                    isMobile={isMobile}
                  />
                ))}
              </SidebarMenuSub>
            </CollapsibleContent>
          </Fragment>
        ) : null}
      </SidebarMenuItem>
    </Collapsible>
  );
};

export const NavMain = ({
  currentUrl,
  menuGroups,
  isMobile,
}: {
  currentUrl: string;
  menuGroups: MenuGroupData[];
  isMobile?: boolean;
}) => {
  return (
    <Fragment>
      {menuGroups?.map((menuGroup) => (
        <SidebarGroup key={menuGroup.group}>
          <SidebarGroupLabel>{menuGroup.group}</SidebarGroupLabel>
          <SidebarMenu>
            {menuGroup.items.map((item) => {
              return (
                <CollapsibleMenuGroup
                  key={item.url || item.title}
                  item={item}
                  currentUrl={currentUrl}
                  isMobile={isMobile}
                />
              );
            })}
          </SidebarMenu>
        </SidebarGroup>
      ))}
    </Fragment>
  );
};

import {
  SidebarGroup,
  SidebarGroupContent,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "@/components/ui/sidebar";
import { getGlobalLinkComponent } from "@/components/fsui/fscommon";

import type { MenuGroupData } from "./menu";
import type * as React from "react";

export function NavSecondary({
  menuGroups,
  ...props
}: {
  menuGroups?: MenuGroupData[];
} & React.ComponentPropsWithoutRef<typeof SidebarGroup>) {
  const Link = getGlobalLinkComponent();
  return menuGroups?.map?.((group) => (
    <SidebarGroup
      {...props}
      key={group.group}
    >
      <SidebarGroupContent>
        <SidebarMenu>
          {group.items.map((item) => (
            <SidebarMenuItem key={item.title}>
              <SidebarMenuButton
                asChild
                size="sm"
              >
                <Link
                  href={item.url}
                  title={item.title}
                >
                  {item.icon && <item.icon />}
                  <span>{item.title}</span>
                </Link>
              </SidebarMenuButton>
            </SidebarMenuItem>
          ))}
        </SidebarMenu>
      </SidebarGroupContent>
    </SidebarGroup>
  ));
}

import { useFastSchema } from "fastschema/react";
import {
  BadgeCheck,
  ChevronsUpDown,
  LifeBuoy,
  LogOut,
} from "lucide-react";

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  useSidebar,
} from "@/components/ui/sidebar";
import { getGlobalNavigateFunction } from "@/components/fsui/fscommon";

export function NavUser() {
  const { isMobile } = useSidebar();
  const { fastschema } = useFastSchema();
  const { authUser } = fastschema.state();
  const navigate = getGlobalNavigateFunction();

  const name =
    authUser?.first_name && authUser?.last_name
      ? `${authUser.first_name} ${authUser.last_name}`
      : authUser?.username || authUser?.email || "User";
  const shortName = name
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);

  return (
    <SidebarMenu>
      <SidebarMenuItem>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <SidebarMenuButton
              size="lg"
              className="data-[state=open]:bg-sidebar-accent data-[state=open]:text-sidebar-accent-foreground cursor-pointer"
            >
              <Avatar className="h-8 w-8 rounded-lg">
                <AvatarImage
                  // src={authUser.avatar}
                  alt={name}
                />
                <AvatarFallback className="rounded-lg">
                  {shortName}
                </AvatarFallback>
              </Avatar>
              <div className="grid flex-1 text-left text-sm leading-tight">
                <span className="truncate font-medium">{name}</span>
                <span className="truncate text-xs">{authUser?.email}</span>
              </div>
              <ChevronsUpDown className="ml-auto size-4" />
            </SidebarMenuButton>
          </DropdownMenuTrigger>
          <DropdownMenuContent
            className="w-(--radix-dropdown-menu-trigger-width) min-w-56 rounded-lg"
            side={isMobile ? "bottom" : "right"}
            align="end"
            sideOffset={4}
          >
            <DropdownMenuLabel className="p-0 font-normal">
              <div className="flex items-center gap-2 px-1 py-1.5 text-left text-sm">
                <Avatar className="h-8 w-8 rounded-lg">
                  <AvatarImage
                    // src={authUser?.avatar}
                    alt={name}
                  />
                  <AvatarFallback className="rounded-lg">
                    {shortName}
                  </AvatarFallback>
                </Avatar>
                <div className="grid flex-1 text-left text-sm leading-tight">
                  <span className="truncate font-medium">{name}</span>
                  <span className="truncate text-xs">{authUser?.email}</span>
                </div>
              </div>
            </DropdownMenuLabel>
            <DropdownMenuSeparator />
            <DropdownMenuGroup>
              <DropdownMenuItem
                className="cursor-pointer"
                onClick={() => {
                  // Open the signed-in user's own record in the existing
                  // user-edit screen; skip when the id is unavailable.
                  if (authUser?.id !== undefined) {
                    navigate(`/users/edit?id=${authUser.id}`);
                  }
                }}
              >
                <BadgeCheck />
                Account
              </DropdownMenuItem>
            </DropdownMenuGroup>
            <DropdownMenuSeparator />
            <DropdownMenuGroup>
              <DropdownMenuItem
                asChild
                className="cursor-pointer"
              >
                <a
                  href="https://fastschema.com/docs"
                  target="_blank"
                  rel="noreferrer"
                >
                  <LifeBuoy />
                  Help
                </a>
              </DropdownMenuItem>
            </DropdownMenuGroup>
            <DropdownMenuSeparator />
            <DropdownMenuItem
              className="cursor-pointer"
              onClick={async () => {
                await fastschema.auth().logout();
                navigate("/login");
              }}
            >
              <LogOut />
              Log out
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </SidebarMenuItem>
    </SidebarMenu>
  );
}

import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  useSidebar,
} from "@/components/ui/sidebar";
import {
  FastSchemaLogoIcon,
  getGlobalLinkComponent,
} from "@/components/fsui/fscommon";

import { NavMain } from "./nav-main";
import { NavSecondary } from "./nav-secondary";
import { NavUser } from "./nav-user";

import type { MenuGroupData } from "./menu";
import type * as React from "react";

export const AppSidebar = ({
  currentUrl,
  logo,
  menus,
  sidebarProps,
}: {
  currentUrl: string;
  menus: {
    main?: MenuGroupData[];
    secondary?: MenuGroupData[];
  };
  logo?: {
    icon?: React.ReactNode;
    title?: string;
    description?: string;
  };
  sidebarProps?: React.ComponentProps<typeof Sidebar>;
}) => {
  const { isMobile } = useSidebar();
  const Link = getGlobalLinkComponent();
  const logoElm = (
    <Link href="/">
      <div className="text-sidebar-primary-foreground flex aspect-square size-9 items-center justify-center rounded-lg">
        {logo?.icon ?? <FastSchemaLogoIcon />}
      </div>
      <div className="grid flex-1 text-left text-sm leading-tight">
        <span className="truncate font-medium">
          {logo?.title ?? "FastSchema"}
        </span>
        <span className="truncate text-xs">
          {logo?.description ?? "Backend As A Service"}
        </span>
      </div>
    </Link>
  );
  return (
    <Sidebar
      variant="inset"
      className="select-none"
      {...sidebarProps}
    >
      <SidebarHeader>
        <SidebarMenu>
          <SidebarMenuItem>
            <SidebarMenuButton
              size="lg"
              asChild
            >
              {logoElm}
            </SidebarMenuButton>
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarHeader>
      <SidebarContent>
        <NavMain
          currentUrl={currentUrl}
          isMobile={isMobile}
          menuGroups={menus.main || []}
        />
        <NavSecondary
          className="mt-auto"
          menuGroups={menus.secondary || []}
        />
      </SidebarContent>
      <SidebarFooter>
        <NavUser />
      </SidebarFooter>
    </Sidebar>
  );
};

import { useEffect } from "react";
import { create } from "zustand";

export type BreadcrumbType = {
  title: string;
  href?: string;
};

export type PageInfo = {
  title?: string;
  breadcrumbs?: BreadcrumbType[];
  actions?: React.ReactNode;
  hasUnsavedChanges?: boolean;
};

export const defaultPageInfo: PageInfo = {
  title: "FastSchema",
  hasUnsavedChanges: false,
  breadcrumbs: [
    {
      title: "Dashboard",
      href: "/",
    },
  ],
};

export type AppLayoutState = {
  pageInfo: PageInfo;
  setPageInfo: (info: PageInfo) => void;
};

export const useAppLayoutState = create<AppLayoutState>((set) => ({
  pageInfo: defaultPageInfo,
  setPageInfo: (pageInfo: PageInfo) => {
    set({
      pageInfo: {
        ...pageInfo,
        breadcrumbs: [
          { title: "Dashboard", href: "/" },
          ...(pageInfo.breadcrumbs || []),
        ],
      },
    });
  },
}));

export const usePageInfo = () => {
  return useAppLayoutState((state) => state.pageInfo);
};

export const useSetPageInfo = (pageInfo: PageInfo) => {
  const setPageInfo = useAppLayoutState((state) => state.setPageInfo);
  useEffect(() => {
    setPageInfo(pageInfo);
    return () =>
      setPageInfo({
        title: defaultPageInfo.title,
        hasUnsavedChanges: false,
      });
  }, [pageInfo, setPageInfo]);
};

export const setPageInfo = (pageInfo: PageInfo) => {
  useAppLayoutState.getState().setPageInfo(pageInfo);
};
